import{c as r,Q as a,j as e,m as o}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"天津大学","description":"天津大学精仪学院/脑机交互与人机共融海河实验室博士项目指南 — 脑机接口国家重点方向","frontmatter":{"title":"天津大学","description":"天津大学精仪学院/脑机交互与人机共融海河实验室博士项目指南 — 脑机接口国家重点方向","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bci","bme"],"tags":["天津大学","天津",985],"admission-year":2027},"headers":[],"relativePath":"universities/tju.md","filePath":"universities/tju.md","lastUpdated":1780110618000}'),l={name:"universities/tju.md"};function n(i,t,s,u,d,h){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="天津大学" tabindex="-1">天津大学 <a class="header-anchor" href="#天津大学" aria-label="Permalink to &quot;天津大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>天津大学在脑机接口领域具有独特地位：<strong>2025年新增设置全国首个&quot;脑机接口&quot;一级学科博士点</strong>，构建起从本科（2024年开设全国首个脑机接口本科专业方向）到博士的完整贯通培养体系。依托<strong>脑机交互与人机共融海河实验室</strong>，天大在非侵入式BCI、脑电信号处理、神经康复工程方向处于国内领先地位。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.tju.edu.cn" target="_blank" rel="noreferrer">https://www.tju.edu.cn</a></li><li>研究生院: <a href="http://gs.tju.edu.cn" target="_blank" rel="noreferrer">http://gs.tju.edu.cn</a></li><li>精仪学院: <a href="http://jyxy.tju.edu.cn" target="_blank" rel="noreferrer">http://jyxy.tju.edu.cn</a></li><li>医学部: <a href="http://mctu.tju.edu.cn" target="_blank" rel="noreferrer">http://mctu.tju.edu.cn</a></li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-脑机接口-神经工程方向-——" tabindex="-1">—— 脑机接口 / 神经工程方向 —— <a class="header-anchor" href="#——-脑机接口-神经工程方向-——" aria-label="Permalink to &quot;—— 脑机接口 / 神经工程方向 ——&quot;">​</a></h3><h4 id="明东-—-教授、博导、副校长" tabindex="-1">明东 — 教授、博导、副校长 <a class="header-anchor" href="#明东-—-教授、博导、副校长" aria-label="Permalink to &quot;明东 — 教授、博导、副校长&quot;">​</a></h4><ul><li><strong>职务</strong>: 天津大学<strong>副校长</strong>、医学部<strong>主任</strong>、脑机交互与人机共融海河实验室<strong>主任</strong></li><li><strong>身份</strong>: 全国政协委员、九三学社中央科技专委会副主任</li><li><strong>荣誉</strong>: 中国科协求是杰出青年奖、&quot;九三楷模&quot;、三度获国家级教学成果奖</li></ul><p><strong>研究方向</strong>:</p><ul><li>神经工程（非侵入式BCI）</li><li>脑电信号处理</li><li>神经康复工程</li><li>片上脑机接口（离体BCI）— 2024年提出全新方向，体外培养神经组织与机器连接</li></ul><p><strong>代表性成果</strong>:</p><table tabindex="0"><thead><tr><th>成果</th><th>说明</th></tr></thead><tbody><tr><td><strong>&quot;神工&quot;系列</strong></td><td>脑机交互创新医疗器械全谱系产品（神工-神机/神行/神甲/灵犀指），累计服务3000+脑卒中患者</td></tr><tr><td><strong>&quot;脑语者&quot;芯片</strong></td><td>全球首款脑机接口专用采集与编解码芯片</td></tr><tr><td><strong>空间站脑机交互系统</strong></td><td>国际首套，成功应用于&quot;天宫二号&quot;和&quot;神舟十一号&quot;载人飞行任务</td></tr><tr><td><strong>片上脑机接口</strong></td><td>2024年提出全新方向，体外培养干细胞神经组织实现与机器连接</td></tr><tr><td><strong>无创颅内压监测</strong></td><td>光学脑机接口技术，精度达0.05 mmHg，全球最高精度</td></tr></tbody></table><p><strong>2026年博士生招生</strong>: 是（脑机接口一级学科博士点）</p><blockquote><p>明东同时担任副校长职务，其团队还有多位合作导师。建议同时关注海河实验室其他PI。</p></blockquote><hr><h2 id="脑机接口-一级学科博士点" tabindex="-1">&quot;脑机接口&quot;一级学科博士点 <a class="header-anchor" href="#脑机接口-一级学科博士点" aria-label="Permalink to &quot;&quot;脑机接口&quot;一级学科博士点&quot;">​</a></h2><h3 id="招生方向" tabindex="-1">招生方向 <a class="header-anchor" href="#招生方向" aria-label="Permalink to &quot;招生方向&quot;">​</a></h3><ul><li>脑机接口 + 人工智能</li><li>脑机接口 + 集成电路</li><li>脑机接口 + 临床医学</li><li>脑机接口 + 材料科学</li></ul><h3 id="实验室平台" tabindex="-1">实验室平台 <a class="header-anchor" href="#实验室平台" aria-label="Permalink to &quot;实验室平台&quot;">​</a></h3><p>依托<strong>脑机交互与人机共融海河实验室</strong>，拥有&quot;临床诊疗—技术研发—产品注册—医保接入&quot;的完整闭环链路。</p><h3 id="人才需求" tabindex="-1">人才需求 <a class="header-anchor" href="#人才需求" aria-label="Permalink to &quot;人才需求&quot;">​</a></h3><p>据明东2026年两会发言，到2030年我国脑机接口人才缺口将达20余万人。天大正加快布局脑机接口人才长周期贯通培养体系。</p><hr><h2 id="_2026年博士招生-参考" tabindex="-1">2026年博士招生（参考） <a class="header-anchor" href="#_2026年博士招生-参考" aria-label="Permalink to &quot;2026年博士招生（参考）&quot;">​</a></h2><ul><li>招生方式: 申请考核制</li><li>报名时间: 通常在2025年10月-12月</li><li>可申请专业: 脑机接口（新）、生物医学工程、仪器科学与技术</li></ul><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>天大是国内BCI方向最具特色的高校之一</strong>：全国首个BCI博士点，学科专注度高</li><li><strong>片上脑机接口方向与你的类脑器官经验高度吻合</strong>：明东2024年提出的离体BCI方向，直接用干细胞培养的神经组织作为BCI接口。你的脑类器官培养+钙成像经验是独特优势</li><li><strong>&quot;脑语者&quot;芯片方向</strong>：你的电路设计经验可与芯片应用层衔接</li><li><strong>非侵入式BCI康复方向</strong>：你的EMG反馈系统经验可作为切入点</li><li><strong>建议在联系邮件中突出</strong>：类脑器官BCI经验（这是明东团队最新方向）+ 硬件开发全栈能力</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="http://news.tju.edu.cn" target="_blank" rel="noreferrer">天大新闻</a> — 明东教授相关报道（访问日期: 2026-05-25）</li><li><a href="http://gs.tju.edu.cn" target="_blank" rel="noreferrer">天大研招网</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以天津大学研究生院官网最新公告为准。</em></p>',36)])])}const q=r(l,[["render",n]]);export{c as __pageData,q as default};
